import React, { useEffect, useState } from "react";

const TravelHistory = ({ employee }) => {
  const [travelData, setTravelData] = useState([]);

  useEffect(() => {
    if (employee?.empId || employee?.empld) {
      fetchData();
    }
  }, [employee]);

  const fetchData = async () => {
    try {
      const empId = employee.empId || employee.empld;

      const response = await fetch(
        `https://prasa-app-yde3.onrender.com/travel-expenses?empId=${empId}`
      );

      const data = await response.json();
      console.log("TRAVEL RESPONSE FROM BACKEND:", data);

      if (Array.isArray(data)) {
        setTravelData(data);
      } else {
        setTravelData([]);
      }
    } catch (error) {
      console.error(error);
      setTravelData([]);
    }
  };

  return (
    <div className="history-container">
      <h2>Travel Expense History</h2>

      <table className="history-table">
        <thead>
          <tr>
            <th>Date</th>
            <th>Purpose</th>
            <th>From</th>
            <th>To</th>
            <th>Amount</th>
          </tr>
        </thead>

        <tbody>
          {travelData.length > 0 ? (
            travelData.map((item) => (
              <tr key={item.id}>
                <td>{item.travel_date}</td>
                <td>{item.purpose}</td>
                <td>{item.location_from}</td>
                <td>{item.location_to}</td>
                <td>₹{item.amount}</td>
              </tr>
            ))
          ) : (
            <tr>
              <td colSpan="5" style={{ textAlign: "center" }}>
                No records found
              </td>
            </tr>
          )}
        </tbody>
      </table>
    </div>
  );
};

export default TravelHistory;
